  ('heelevel3-1fb53453-moex-00030', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-114-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '有關緊急命令之敘述，下列何者正確？', '["緊急命令之授權依據為一般法律", "緊急命令得暫時取代法律、變更法律", "緊急命令是由行政院院長發布", "緊急命令目的在於處理緊急危難或應付財經重大變故，故無須立法院之同意追認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:28+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00031', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-114-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '依行政程序法規定，關於行政指導之敘述，下列何者正確？', '["行政指導無須以特定人為對象", "行政指導具有法律上之強制力", "相對人若明確拒絕指導時，行政機關應即停止行政指導，並不得據此對相對人為不利之處置", "針對非其職權或職掌之事務，行政機關仍得為行政指導 21250–21350 22150 22950–23050 23250、23450"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:28+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
